export function closureExpression(
  parametersOrConfig: ClosureParameters | ClosureExpressionConfig,
  config?: Partial<ClosureExpressionConfig>,
): ClosureExpressionNode {
  const fields: any = isNodeData(parametersOrConfig)
    ? { 'parameters': parametersOrConfig, ...config }
    : parametersOrConfig;
  const node: any = { type: 'closure_expression', fields };
  node.returnType = (v: any) => { fields['return_type'] = v; return node; };
  node.body = (v: any) => { fields['body'] = v; return node; };
  node.render = () => render(node, rules, joinBy);
  node.toEdit = (startOrRange: any, endPos?: number) => {
    if (typeof startOrRange === 'number') return toEdit(node, rules, startOrRange, endPos!, joinBy);
    return toEdit(node, rules, startOrRange, joinBy);
  };
  node.replace = (target: any) => { const r = target.range(); return toEdit(node, rules, r, joinBy); };
  return node;
}

closureExpression.assign = function(target: TreeNode<'closure_expression'>): ClosureExpressionNode {
  const result = closureExpression({
    parameters: closureParameters.assign(target.field('parameters')!),
    return_type: target.field('return_type') ? assignByKind[target.field('return_type')!.type]!(target.field('return_type')!) : undefined,
    body: assignByKind[target.field('body')!.type]!(target.field('body')!),
  } as any);
  const _origToEdit = result.toEdit;
  result.toEdit = (...args: any[]) => {
    if (args.length === 0) {
      const r = target.range();
      return { startPos: r.start.index, endPos: r.end.index, insertedText: result.render() };
    }
    return _origToEdit(...args);
  };
  result.replace = () => result.toEdit();
  return result;
} as any;

