export function closureParameters(
  childrenOrConfig?: (StringLiteral | RawStringLiteral | CharLiteral | BooleanLiteral | IntegerLiteral | FloatLiteral | NegativeLiteral | Identifier | ScopedIdentifier | GenericPattern | TuplePattern | TupleStructPattern | StructPattern | RefPattern | SlicePattern | CapturedPattern | ReferencePattern | RemainingFieldPattern | MutPattern | RangePattern | OrPattern | ConstBlock | MacroInvocation | Parameter) | (StringLiteral | RawStringLiteral | CharLiteral | BooleanLiteral | IntegerLiteral | FloatLiteral | NegativeLiteral | Identifier | ScopedIdentifier | GenericPattern | TuplePattern | TupleStructPattern | StructPattern | RefPattern | SlicePattern | CapturedPattern | ReferencePattern | RemainingFieldPattern | MutPattern | RangePattern | OrPattern | ConstBlock | MacroInvocation | Parameter)[] | ClosureParametersConfig,
): ClosureParametersNode {
  let fields: any;
  if (Array.isArray(childrenOrConfig)) {
    fields = { children: childrenOrConfig };
  } else if (childrenOrConfig && isNodeData(childrenOrConfig)) {
    fields = { children: [childrenOrConfig] };
  } else {
    fields = childrenOrConfig ?? {};
  }
  const node: any = { type: 'closure_parameters', fields };
  node.children = (...v: any[]) => { fields.children = v; return node; };
  node.render = () => render(node, rules, joinBy);
  node.toEdit = (startOrRange: any, endPos?: number) => {
    if (typeof startOrRange === 'number') return toEdit(node, rules, startOrRange, endPos!, joinBy);
    return toEdit(node, rules, startOrRange, joinBy);
  };
  node.replace = (target: any) => { const r = target.range(); return toEdit(node, rules, r, joinBy); };
  return node;
}

