export function letDeclaration(
  patternOrConfig: StringLiteral | RawStringLiteral | CharLiteral | BooleanLiteral | IntegerLiteral | FloatLiteral | NegativeLiteral | Identifier | ScopedIdentifier | GenericPattern | TuplePattern | TupleStructPattern | StructPattern | RefPattern | SlicePattern | CapturedPattern | ReferencePattern | RemainingFieldPattern | MutPattern | RangePattern | OrPattern | ConstBlock | MacroInvocation | LetDeclarationConfig,
  config?: Partial<LetDeclarationConfig>,
): LetDeclarationNode {
  const fields: any = isNodeData(patternOrConfig)
    ? { 'pattern': patternOrConfig, ...config }
    : patternOrConfig;
  const node: any = { type: 'let_declaration', fields };
  node.typeField = (v: any) => { fields['type'] = v; return node; };
  node.value = (v: any) => { fields['value'] = v; return node; };
  node.alternative = (v: any) => { fields['alternative'] = v; return node; };
  node.children = (...v: any[]) => { fields.children = v; return node; };
  node.render = () => render(node, rules, joinBy);
  node.toEdit = (startOrRange: any, endPos?: number) => {
    if (typeof startOrRange === 'number') return toEdit(node, rules, startOrRange, endPos!, joinBy);
    return toEdit(node, rules, startOrRange, joinBy);
  };
  node.replace = (target: any) => { const r = target.range(); return toEdit(node, rules, r, joinBy); };
  return node;
}

letDeclaration.assign = function(target: TreeNode<'let_declaration'>): LetDeclarationNode {
  const result = letDeclaration({
    pattern: assignByKind[target.field('pattern')!.type]!(target.field('pattern')!),
    type: target.field('type') ? assignByKind[target.field('type')!.type]!(target.field('type')!) : undefined,
    value: target.field('value') ? assignByKind[target.field('value')!.type]!(target.field('value')!) : undefined,
    alternative: target.field('alternative') ? block.assign(target.field('alternative')!) : undefined,
  } as any);
  const _origToEdit = result.toEdit;
  result.toEdit = (...args: any[]) => {
    if (args.length === 0) {
      const r = target.range();
      return { startPos: r.start.index, endPos: r.end.index, insertedText: result.render() };
    }
    return _origToEdit(...args);
  };
  result.replace = () => result.toEdit();
  return result;
} as any;

